#include <bits/stdc++.h>
using namespace std;

const int N=2003,mod=1e9+7;

int n,h[N][80],len[N],f[N],ans;
char s[80];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%s",s+1);
        len[i]=strlen(s+1);
        for(int j=1;j<=len[i];j++)
            h[i][j]=(1LL*h[i][j-1]*31+s[j]-'a'+1)%mod;
    }
    for(int i=1;i<=n;i++){
        f[i]=1;
        for(int j=1;j<i;j++)
            if(len[j]<=len[i] && h[j][len[j]]==h[i][len[j]])
                f[i]=max(f[i],f[j]+1);
        ans=max(ans,f[i]);
    }
    printf("%d",ans);
    return 0;
}
